mapper.select:
SELECT fa.id, fa.clinic_id AS clinicId, c.clinic_name AS clinicName, fa.biz_type AS bizType, fa.biz_id AS bizId, fa.patient_id AS patientId, p.patient_name AS patientName, fa.medical_record_id AS medicalRecordId, mr.record_no AS medicalRecordNo, fa.file_name AS fileName, fa.file_ext AS fileExt, fa.mime_type AS mimeType, fa.file_size AS fileSize, fa.storage_type AS storageType, fa.bucket_name AS bucketName, fa.object_key AS objectKey, fa.file_url AS fileUrl, fa.upload_source AS uploadSource, fa.uploader_id AS uploaderId, fa.file_status AS fileStatus, fa.created_at AS createdAt FROM file_attachment fa LEFT JOIN clinic c ON c.id = fa.clinic_id LEFT JOIN patient p ON p.id = fa.patient_id LEFT JOIN medical_record mr ON mr.id = fa.medical_record_id WHERE fa.org_id = #{orgId} AND fa.is_deleted = 0
AND fa.clinic_id = #{query.clinicId}
AND fa.biz_type = #{query.bizType}
AND fa.biz_id = #{query.bizId}
AND fa.patient_id = #{query.patientId}
AND fa.medical_record_id = #{query.medicalRecordId}
ORDER BY fa.created_at DESC, fa.id DESC
